func TestComponent_MultipleConfigValidations(t *testing.T) {
	tests := []struct {
		name      string
		config    Config
		shouldErr bool
	}{
		{
			name: "valid minimal",
			config: Config{
				Ports: &component.PortConfig{
					Inputs: []component.PortDefinition{
						{Name: "entity_watch", Type: "kv-watch", Subject: "ENTITY_STATES"},
					},
					Outputs: []component.PortDefinition{
						{Name: "temporal_index", Type: "kv-write", Subject: "TEMPORAL_INDEX"},
					},
				},
				TimeResolution: "hour",
				Workers:        4,
				BatchSize:      100,
			},
			shouldErr: false,
		},
		{
			name: "valid with minute resolution",
			config: Config{
				Ports: &component.PortConfig{
					Inputs: []component.PortDefinition{
						{Name: "entity_watch", Type: "kv-watch", Subject: "ENTITY_STATES"},
					},
					Outputs: []component.PortDefinition{
						{Name: "temporal_index", Type: "kv-write", Subject: "TEMPORAL_INDEX"},
					},
				},
				TimeResolution: "minute",
				Workers:        8,
				BatchSize:      200,
			},
			shouldErr: false,
		},
		{
			name: "invalid - wrong resolution",
			config: Config{
				Ports: &component.PortConfig{
					Inputs: []component.PortDefinition{
						{Name: "entity_watch", Type: "kv-watch", Subject: "ENTITY_STATES"},
					},
					Outputs: []component.PortDefinition{
						{Name: "temporal_index", Type: "kv-write", Subject: "TEMPORAL_INDEX"},
					},
				},
				TimeResolution: "second",
				Workers:        4,
				BatchSize:      100,
			},
			shouldErr: true,
		},
		{
			name: "invalid - zero workers",
			config: Config{
				Ports: &component.PortConfig{
					Inputs: []component.PortDefinition{
						{Name: "entity_watch", Type: "kv-watch", Subject: "ENTITY_STATES"},
					},
					Outputs: []component.PortDefinition{
						{Name: "temporal_index", Type: "kv-write", Subject: "TEMPORAL_INDEX"},
					},
				},
				TimeResolution: "hour",
				Workers:        0,
				BatchSize:      100,
			},
			shouldErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.config.Validate()
			if tt.shouldErr {
				assert.Error(t, err)
			} else {
				assert.NoError(t, err)
			}
		})
	}
}

